eleteBefore($idx, &$cancelDelete) {\n//     global $misSessionIsAdmin;\n//     // 고객사 정책: 관리자만 삭제 허용\n//     // if ($misSessionIsAdmin !== \'Y\') {\n//     //     $cancelDelete = true;\n//     //     $GLOBALS[\'_client_alert\'] = \'삭제 권한이 없습니다.\';\n//     // }\n// }\n',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
