INSERT IGNORE INTO `mis_menus` (`idx`,`real_pid`,`menu_name`,`brief_title`,`is_menu_hidden`,`new_gidx`,`auth_code`,`gidx`,`wgidx`,`agidx`,`all_list_member`,`w_all_list_member`,`menu_type`,`up_real_pid`,`add_url`,`auto_gubun`,`sort_g2`,`sort_g4`,`sort_g6`,`use_yn`,`hit`,`ip`,`remark`,`wdate`,`wdater`,`last_update`,`last_updater`,`file_last_update`,`file_last_updater`,`compile_date`,`g01`,`g02`,`g03`,`read_only_cond`,`brief_insert_sql`,`g06`,`g07`,`table_name`,`base_filter`,`use_condition`,`delete_query`,`g12`,`g13`,`g14`,`g17`,`dbalias`,`help_update_deny`,`help_title`,`help_contents`,`add_logic`,`add_logic_treat`,`is_use_print`,`is_use_form`,`add_logic_print`,`language_code`,`depth`,`mis_join_pid`,`mis_join_list`,`trans_id`,`is_core_program`,`comment_count`,`protection`,`g08b`,`excel_data`,`excel_data_midx`,`spreadsheets_url`,`spreadsheet_id`) VALUES ('36','speedmis000036','그룹관리','','N','83','01','21',NULL,NULL,'00151,00165,00316,00397,00403',NULL,'01','speedmis000624','','130103','13','1','3','1','0','211.117.56.35','','2021-03-19 19:22:25','00151','2026-04-11 22:56:05','gadmin','2018-10-14 19:25:33','gadmin',NULL,'','100','Y','case when table_m.idx<=94 then 1 else 0 end','(gname,using_level,wdater) values (\'\',\'03\',\'@misSessionUserId\')',' ','N','mis_groups','','','','N','','N','N','',NULL,'기본그룹 및 사용방법','<p>그룹에 정의된 멤버는 전체메뉴관리 각각의 프로그램에 대한 권한을 갖게 됩니다.</p><p> </p><p>아래의 4개 그룹은 사전정의그룹으로서 삭제할 수 없습니다.</p><p><img src=\"data:image/png;base64,\" /></p><p> </p><p>그 외의 그룹들도 상세내역을 삭제하지 않으면 삭제되지 않습니다.</p><p> </p>','<?php\r\n\r\n\r\nfunction list_json_init() {\r\n    global $actionFlag, $gubun, $misSessionUserId, $isFirstLoad;\r\n    // 목록 데이터 로딩 전에 실행되는 초기화 로직\r\n    //$GLOBALS[\'_client_alert\'] = $misSessionUserId;\r\n    //if($isFirstLoad === true ) {\r\n    //  $GLOBALS[\'_client_openTab\'] = [\r\n    //      \'gubun\' => 314,\r\n    //      \'label\' => \'대시보드\',\r\n    //  ];\r\n    //}\r\n}\r\n\r\nfunction list_json_load(&$data) {\r\n    // $data: 목록 데이터 배열 (각 행을 수정 가능)\r\n        //$data[\'gname\'] = $data[\'gname\'] . \" | hahaha\";\r\n        //$data[\'__html\'][\'gname\'] = \'<a href=\"https://naver.com\" target=\"_blank\">zzz\' . $data[\'gname\'] . \'</a>\';\r\n}\r\n\r\nfunction before_query($menu, $fields, $params) {\r\n    global $actionFlag, $gubun, $idx, $misSessionUserId, $__pdo;\r\n    // 리스트·조회·수정·저장 모든 액션에서 쿼리 생성 전에 호출됨\r\n    // $menu: 메뉴 정보 배열 (table_name, real_pid 등)\r\n    // $fields: 필드 정의 배열\r\n    // $params: 요청 파라미터 (gubun, idx, allFilter, page 등)\r\n    //\r\n    // 예) 전역변수 세팅\r\n    // $GLOBALS[\'my_var\'] = $__pdo->query(\"SELECT ...\")->fetchColumn();\r\n\r\n      // 여러 쿼리 한번에\r\n    $sql = \"update mis_groups set remark=concat(remark,\'.\') where idx=\'$idx\';\";\r\n    $result = execSql($sql);\r\n\r\n    // 결과 확인\r\n    if ($result[\'resultCode\'] === \'success\') {\r\n        $result[\'resultMessage\'] = \'성공!!\';\r\n    } else {\r\n        // 실패 — $result[\'resultMessage\']\r\n    }\r\n    \r\n}\r\nfunction save_updateReady(&$saveList) {\r\n      global $__pdo, $idx;\r\n\r\n      // 값 검증\r\n      if ($saveList[\'gname\']==\'바보\') {\r\n          $GLOBALS[\'_client_confirm\'] = \'바보라고요? 정말로 저장할까요?\';\r\n          return;\r\n      }\r\n\r\n}',NULL,'1','0','<style>\n  .nts { width:100%; max-width:780px; margin:0 auto; font-family:\'Malgun Gothic\',\'맑은 고딕\',sans-serif; color:#000; }\n  .nts table { width:100%; border-collapse:collapse; }\n  .nts th, .nts td { border:1px solid #000; padding:4px 8px; font-size:12px; vertical-align:middle; }\n  .nts th { background:#f5f5f5; font-weight:600; text-align:center; }\n  .nts .title-row { background:#d9e2f3; text-align:center; font-size:16px; font-weight:700; letter-spacing:6px; padding:10px; }\n  .nts .section-title { background:#e8ecf4; text-align:center; font-weight:700; font-size:13px; padding:6px; }\n  .nts .doc-no { font-size:11px; color:#666; text-align:center; margin-bottom:4px; }\n  .nts .center { text-align:center; }\n  .nts .right { text-align:right; }\n  .nts .sub td, .nts .sub th { font-size:11px; padding:3px 6px; }\n  .nts .footer { margin-top:24px; text-align:center; font-size:13px; font-weight:700; }\n  .nts .sign { margin-top:20px; text-align:right; font-size:13px; padding-right:20px; }\n</style>\n\n<div class=\"nts\">\n\n  <div class=\"doc-no\">[관리번호 {{idx}}]</div>\n\n  <table>\n    <tr><td class=\"title-row\" colspan=\"4\">그 룹 관 리 대 장</td></tr>\n  </table>\n\n  <table style=\"margin-top:-1px\">\n    <colgroup><col style=\"width:120px\"><col><col style=\"width:120px\"><col></colgroup>\n    <tr>\n      <th>그룹 번호</th>\n      <td>{{idx}}</td>\n      <th>작성일자</th>\n      <td>{{wdate}}</td>\n    </tr>\n    <tr>\n      <th>그 룹 명</th>\n      <td colspan=\"3\" style=\"font-size:14px;font-weight:700\">{{gname}}</td>\n    </tr>\n    <tr>\n      <th>비 고</th>\n      <td colspan=\"3\">{{remark}}</td>\n    </tr>\n  </table>\n\n  <table style=\"margin-top:8px\">\n    <tr><td class=\"section-title\" colspan=\"5\">소 속 멤 버 현 황</td></tr>\n  </table>\n  <table class=\"sub\" style=\"margin-top:-1px\">\n    <colgroup>\n      <col style=\"width:40px\"><col style=\"width:50px\"><col><col style=\"width:140px\"><col style=\"width:80px\">\n    </colgroup>\n    <thead>\n      <tr><th>순번</th><th>No.</th><th>성 명</th><th>사 번 (ID)</th><th>권 한</th></tr>\n    </thead>\n    <tbody>\n      {{#each zmembeohwagin}}\n      <tr>\n        <td class=\"center\">{{@index}}</td>\n        <td class=\"center\">{{idx}}</td>\n        <td>{{table_user_id_qnuser_name}}</td>\n        <td class=\"center\">{{user_id}}</td>\n        <td class=\"center\">{{zgwonhan}}</td>\n      </tr>\n      {{/each}}\n    </tbody>\n  </table>\n\n  <div class=\"footer\">위와 같이 그룹 멤버 현황을 확인합니다.</div>\n  <div class=\"sign\">담당자: _______________&nbsp;&nbsp;&nbsp;&nbsp;(인)</div>\n\n</div>','ko','3','',NULL,'G3bGOnzs','Y',NULL,'1',NULL,NULL,NULL,NULL,NULL);
