INSERT IGNORE INTO `mis_menus` (`idx`,`real_pid`,`menu_name`,`brief_title`,`is_menu_hidden`,`new_gidx`,`auth_code`,`gidx`,`wgidx`,`agidx`,`all_list_member`,`w_all_list_member`,`menu_type`,`up_real_pid`,`add_url`,`auto_gubun`,`sort_g2`,`sort_g4`,`sort_g6`,`use_yn`,`hit`,`ip`,`remark`,`wdate`,`wdater`,`last_update`,`last_updater`,`file_last_update`,`file_last_updater`,`compile_date`,`g01`,`g02`,`g03`,`read_only_cond`,`brief_insert_sql`,`g06`,`g07`,`table_name`,`base_filter`,`use_condition`,`delete_query`,`g12`,`g13`,`g14`,`g17`,`dbalias`,`help_update_deny`,`help_title`,`help_contents`,`add_logic`,`add_logic_treat`,`is_use_print`,`is_use_form`,`add_logic_print`,`language_code`,`depth`,`mis_join_pid`,`mis_join_list`,`trans_id`,`is_core_program`,`comment_count`,`protection`,`g08b`,`excel_data`,`excel_data_midx`,`spreadsheets_url`,`spreadsheet_id`) VALUES ('266','speedmis000266','웹소스관리(업무용MIS)','','N','83','01','21','0',NULL,'00151,00165,00316,00397,00403',NULL,'01','speedmis000625','','130401','13','4','1','1','0','211.58.59.76','','2021-09-15 13:15:07','00151','2026-04-10 17:46:56','admin','2018-10-14 19:25:33','gadmin','2013-06-11 09:13:42','simple_list','0','N','','','','N','mis_menus','and table_m.menu_type = \'01\'','','useflag=0','N','','N','N','',NULL,'','','<?php\n/**\n * 웹소스관리(업무용MIS) — 266번 프로그램 훅\n * add_logic       → programs/{real_pid}.php        (서버로직)\n * add_logic_print → programs/{real_pid}_print.html  (인쇄양식)\n */\n  function list_json_load(&$data) {\n      // realPid로 탭 열기\n      $data[\'__html\'][\'table_m_qmidx\'] = openTabBtn(\'연결\', [\n              \'real_pid\' => $data[\'real_pid\']\n          ]). $data[\'table_m_qmidx\'];\n\n  }\n\n\nfunction view_load(&$row) {\n    $realPid = trim($row[\'real_pid\'] ?? \'\');\n    if ($realPid === \'\') return;\n\n    // 서버로직: 파일 우선\n    $logicFile = PROGRAMS_PATH . \"/{$realPid}.php\";\n    if (file_exists($logicFile)) {\n        $row[\'add_logic\'] = file_get_contents($logicFile);\n    }\n\n    // 인쇄양식: 파일 우선\n    $printFile = PROGRAMS_PATH . \"/{$realPid}_print.html\";\n    if (file_exists($printFile)) {\n        $row[\'add_logic_print\'] = file_get_contents($printFile);\n    }\n}\n\nfunction save_updateAfter($idx, &$afterScript) {\n    $pdo = $GLOBALS[\'__pdo\'] ?? null;\n    if (!$pdo) return;\n\n    $stmt = $pdo->prepare(\'SELECT real_pid, add_logic, add_logic_print FROM mis_menus WHERE idx = ? LIMIT 1\');\n    $stmt->execute([$idx]);\n    $row = $stmt->fetch(\\PDO::FETCH_ASSOC);\n    if (!$row || empty(trim($row[\'real_pid\'] ?? \'\'))) return;\n\n    $realPid = trim($row[\'real_pid\']);\n\n    // ── 서버로직 파일 동기화 ──\n    _syncFile(PROGRAMS_PATH . \"/{$realPid}.php\", trim($row[\'add_logic\'] ?? \'\'), true);\n\n    // ── 인쇄양식 파일 동기화 ──\n    _syncFile(PROGRAMS_PATH . \"/{$realPid}_print.html\", trim($row[\'add_logic_print\'] ?? \'\'), false);\n}\n\nfunction _syncFile(string $filePath, string $code, bool $phpTag): void {\n    if ($code === \'\') {\n        if (file_exists($filePath)) @unlink($filePath);\n        return;\n    }\n    if ($phpTag && stripos(ltrim($code), \'<?php\') !== 0) {\n        $code = \"<?php\\n\" . $code;\n    }\n    @file_put_contents($filePath, $code);\n}',NULL,'0','0','','ko','3',NULL,',\'766\'','xrIlp53j','Y',NULL,'1',NULL,NULL,NULL,NULL,NULL);
